class SessionManager:
    def __init__(self, redis_client, prefix='session:'):
        self.redis_client = redis_client
        self.prefix = prefix
        self.default_ttl = 86400

    def create_session(self, user_id, data=None):
        session_id = secrets.token_urlsafe(32)
        session_key = f"{self.prefix}{session_id}"
        
        session_data = {
            'user_id': user_id,
            'created_at': str(redis_client.time()[0])
        }
        
        if data:
            session_data.update(data)
        
        self.redis_client.setex(
            session_key,
            self.default_ttl,
            json.dumps(session_data)
        )
        
        return session_id

    def get_session(self, session_id):
        session_key = f"{self.prefix}{session_id}"
        data = self.redis_client.get(session_key)
        
        if data:
            return json.loads(data)
        return None

    def update_session(self, session_id, data):
        session_key = f"{self.prefix}{session_id}"
        existing_data = self.get_session(session_id)
        
        if existing_data:
            existing_data.update(data)
            self.redis_client.setex(
                session_key,
                self.default_ttl,
                json.dumps(existing_data)
            )
            return True
        return False

    def delete_session(self, session_id):
        session_key = f"{self.prefix}{session_id}"
        return self.redis_client.delete(session_key)

    def refresh_session(self, session_id):
        session_key = f"{self.prefix}{session_id}"
        return self.redis_client.expire(session_key, self.default_ttl)

session_manager = SessionManager(redis_client)

def cache_query(ttl=300, prefix='cache:'):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_data = {
                'func': func.__name__,
                'args': args,
                'kwargs': sorted(kwargs.items())
            }
            cache_key_str = json.dumps(cache_key_data, sort_keys=True)
            cache_key_hash = hashlib.sha256(cache_key_str.encode()).hexdigest()
            cache_key = f"{prefix}{cache_key_hash}"
            
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            result = func(*args, **kwargs)
            
            redis_client.setex(
                cache_key,
                ttl,
                json.dumps(result)
            )
            
            return result
        return wrapper
    return decorator

def invalidate_cache(pattern='cache:*'):
    cursor = 0
    while True:
        cursor, keys = redis_client.scan(cursor, match=pattern, count=100)
        if keys:
            redis_client.delete(*keys)
        if cursor == 0:
            break

@cache_query(ttl=600, prefix='db:users:')
def get_user_from_database(user_id):
    import time
    time.sleep(0.1)
    
    return {
        'user_id': user_id,
        'username': f'user_{user_id}',
        'email': f'user_{user_id}@example.com',
        'role': 'user'
    }

@cache_query(ttl=300, prefix='db:products:')
def get_products_from_database(category=None, limit=10):
    import time
    time.sleep(0.2)
    
    products = []
    for i in range(limit):
        products.append({
            'id': i,
            'name': f'Product {i}',
            'category': category or 'general',
            'price': 10.0 + i
        })
    return products

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        return jsonify({'error': 'Username and password required'}), 400
    
    user_id = hashlib.sha256(username.encode()).hexdigest()[:16]
    
    session_id = session_manager.create_session(
        user_id,
        {'username': username, 'ip': request.remote_addr}
    )
    
    response = jsonify({
        'message': 'Login successful',
        'session_id': session_id
    })
    response.set_cookie('session_id', session_id, httponly=True, secure=True, samesite='Strict')
    
    return response

@app.route('/logout', methods=['POST'])
def logout():
    session_id = request.cookies.get('session_id')
    
    if session_id:
        session_manager.delete_session(session_id)
    
    response = jsonify({'message': 'Logout successful'})
    response.set_cookie('session_id', '', expires=0)
    
    return response

@app.route('/profile', methods=['GET'])
def profile():
    session_id = request.cookies.get('session_id')
    
    if not session_id:
        return jsonify({'error': 'Not authenticated'}), 401
    
    session_data = session_manager.get_session(session_id)
    
    if not session_data:
        return jsonify({'error': 'Invalid session'}), 401
    
    session_manager.refresh_session(session_id)
    
    user_data = get_user_from_database(session_data['user_id'])
    
    return jsonify({
        'user': user_data,
        'session': session_data
    })

@app.route('/products', methods=['GET'])
def products():
    category = request.args.get('category')
    limit = int(request.args.get('limit', 10))
    
    products = get_products_from_database(category=category, limit=limit)
    
    return jsonify({'products': products})

@app.route('/cache/clear', methods=['POST'])
def clear_cache():
    session_id = request.cookies.get('session_id')
    
    if not session_id:
        return jsonify({'error': 'Not authenticated'}), 401
    
    session_data = session_manager.get_session(session_id)
    
    if not session_data:
        return jsonify({'error': 'Invalid session'}), 401
    
    pattern = request.get_json().get('pattern', 'cache:*')
    invalidate_cache(pattern)
    
    return jsonify({'message': 'Cache cleared'})

